files.content:
events {}
http {
  log_format json escape=json '{"timestamp":"$time_iso8601","remote_addr":"$remote_addr","request_method":"$request_method","uri":"$request_uri","status":$status,"http_user_agent":"$http_user_agent"}';
  access_log /var/log/nginx/access.jsonl json;
  error_log /var/log/nginx/error.log warn;
  server {
    listen 80;
    root /usr/share/nginx/html;
    index index.html;
    location / {
      try_files $uri $uri/ /index.html;
    }
  }
}
